INSERT INTO orgs (id, name, slug, logo_url, description, city, state, website_url, code_of_conduct) VALUES ('6206da6a-c455-ae6c-168c-c3e94b10c677', 'North County Theatre', 'north-county-theatre', NULL, 'Community theatre bringing stories to life since 1985.', 'Riverside', 'CA', 'https://northcountytheatre.org', 'NCT is committed to a safe, inclusive, and respectful environment for every volunteer, performer, and audience member. We do not tolerate harassment, discrimination, or unsafe behavior of any kind. All company members agree to: treat one another with respect; honor rehearsal and performance commitments; follow safety guidance from stage management; and raise concerns promptly with the production team or board. Minors are always supervised, and guardians are kept informed of schedules and expectations.') ON CONFLICT (id) DO NOTHING;
